function excludePortRange(input) {
  let exposedPorts = input.exposed_ports;
  let lastPort = exposedPorts[exposedPorts.length - 1];
  let excludedRange = lastPort + 1;
  for (let i = 0; i < exposedPorts.length; i++) {
